// src/pages/FarmDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';

function FarmDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // Hợp nhất state của form thành một state duy nhất
  const [activityFormData, setActivityFormData] = useState({
    speciesName: '',
    date: '',
    increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    reasonForChange: '',
  });

  const fetchFarmDetails = useCallback(async () => {
    setLoading(true);
    setError('');
    setMessage('');
    try {
      const resFarm = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setFarm(resFarm.data);

      if (resFarm.data.loaiDongVatRung && Array.isArray(resFarm.data.loaiDongVatRung) && resFarm.data.loaiDongVatRung.length > 0) {
        setActivityFormData(prev => ({
          ...prev,
          speciesName: resFarm.data.loaiDongVatRung[0].tenLamSan
        }));
      }

      const resActivities = await axios.get(`http://localhost:10000/api/farm-activities/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setActivities(resActivities.data);

    } catch (err) {
      setError(err.response?.data?.message || 'Could not load farm details.');
      if (err.response?.status === 404) {
        navigate('/admin/farms');
      }
    } finally {
      setLoading(false);
    }
  }, [farmId, token, navigate]);

  useEffect(() => {
    if (farmId && token) {
      fetchFarmDetails();
    } else {
      setLoading(false);
    }
  }, [farmId, token, fetchFarmDetails]);

  const handleActivityFormChange = (e) => {
    const { name, value } = e.target;
    let newFormData = { ...activityFormData };

    if (['speciesName', 'date', 'reasonForChange'].includes(name)) {
      newFormData[name] = value;
    } else {
      const [mainField, subField, prop] = name.split('.');
      if(newFormData[mainField] && newFormData[mainField][subField]) {
        newFormData = {
          ...newFormData,
          [mainField]: {
            ...newFormData[mainField],
            [subField]: {
              ...newFormData[mainField][subField],
              [prop]: parseInt(value, 10) || 0,
            },
          },
        };
      }
    }
    setActivityFormData(newFormData);
  };

  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      const dataToSend = { ...activityFormData, farm: farmId };
      const res = await axios.post(`http://localhost:10000/api/farm-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setMessage('Tracking record added successfully!');
      setActivities(prevActivities => [...prevActivities, res.data]);
      // Reset form
      setActivityFormData(prev => ({
        ...prev,
        date: '',
        increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        reasonForChange: '',
      }));
    } catch (err) {
      setError(err.response?.data?.message || 'Error adding tracking record.');
    }
  };

  const handleDeleteActivity = async (activityId) => {
    if (window.confirm('Are you sure you want to delete this record?')) {
      try {
        await axios.delete(`http://localhost:10000/api/farm-activities/${activityId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        setMessage('Record deleted successfully.');
        setActivities(prevActivities => prevActivities.filter(act => act._id !== activityId));
      } catch (err) {
        setError(err.response?.data?.message || 'Error deleting tracking record.');
      }
    }
  };

  if (loading) return <div className="form-container"><p>Loading data...</p></div>;
  if (error) return <div className="form-container"><p style={{ color: 'red' }}>Error: {error}</p></div>;
  if (!farm) return <div className="form-container"><p>No farm information found.</p></div>;

  return (
    <div className="form-container">
      <style>{/* CSS của bạn giữ nguyên */}</style>
      
      <h2>👁️ Logbook: {farm.tenCoSo}</h2>
      
      <div className="form-grid">
        <div className="detail-group"><strong>Farm Name:</strong> <p>{farm.tenCoSo}</p></div>
        <div className="detail-group"><strong>Address:</strong> <p>{farm.diaChiCoSo}</p></div>
        <div className="form-group detail-group">
          <label>Species Name:</label>
          <select name="speciesName" value={activityFormData.speciesName} onChange={handleActivityFormChange} required>
            <option value="">-- Select species --</option>
            {farm.loaiDongVatRung?.map((species, index) => (
              <option key={index} value={species.tenLamSan}>{species.tenLamSan}</option>
            ))}
          </select>
        </div>
      </div>

      <h3>Add New Tracking Record:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid">
          <div className="form-group">
            <label>Date Recorded:</label>
            <input type="date" name="date" value={activityFormData.date} onChange={handleActivityFormChange} required />
          </div>
          <div className="form-group">
            <label>Reason for Change:</label>
            <input type="text" name="reasonForChange" value={activityFormData.reasonForChange} onChange={handleActivityFormChange} />
          </div>
        </div>

        <div className="form-grid">
          <div className="form-section-wrapper">
            <h4>Increase:</h4>
            {/* Các input cho Increase */}
            <input type="number" name="increase.parents.male" value={activityFormData.increase.parents.male} onChange={handleActivityFormChange} min="0" />
            {/* ... các input khác */}
          </div>
          <div className="form-section-wrapper">
            <h4>Decrease:</h4>
            {/* Các input cho Decrease */}
            <input type="number" name="decrease.parents.male" value={activityFormData.decrease.parents.male} onChange={handleActivityFormChange} min="0" />
            {/* ... các input khác */}
          </div>
        </div>

        <button type="submit" className="submit-button">Add Record</button>
      </form>

      <h3>Tracking History:</h3>
      <div className="activity-list-container">
        {/* Bảng hiển thị dữ liệu */}
      </div>

      <div className="detail-actions">
        <button onClick={() => navigate('/admin/farms')} className="cancel-button">Back to List</button>
      </div>
    </div>
  );
}

export default FarmDetail;
